597→        const teamRoleMap = new Map<string, ITeamRoleTreeVo>(
598→          listRes.data.records.map((it) => {
599→            if (it.teamId === '0') {
600→              return [
601→                rootTeam.teamId,
602→                {
603→                  ...it,
