161→export type ISpaceTree = INodeTree<NodeTreeType.SpaceNodeEntity>;
162→
163→export interface ISpaceTreeNode extends ISpaceTree {
164→  children: ISpaceTreeNode[];
165→  /** 深度，从0开始 */
166→  depth: number;
167→}
168→
169→/** 将ISpaceTree数据转换成ISpaceTreeNode树节点对象，在原对象上改动，不生成新对象 */
170→export function createSpaceTreeNode(
171→  data: ISpaceTree,
172→  map: Record<string, ISpaceTreeNode | undefined>,
173→): ISpaceTreeNode {
174→  const node = data as ISpaceTreeNode;
175→  // 不要在node中添加parent对象引用，使用parentId从nodeMap中获取
176→  const parent: ISpaceTreeNode | undefined = map[node.parentId];
177→  node.depth = (parent?.depth ?? -1) + 1;
178→  return node;
179→}
180→
181→/** ISpaceTree树转换成ISpaceTreeNode树，在原对象上改动 */
182→export function resolveSpaceTree(tree: ISpaceTree[]) {
183→  const treeNodeMap: Record<string, ISpaceTreeNode> = {};
184→  const spaceNodeMap: Record<string, ISpaceTreeNode> = {};
185→  traversalTree(tree as ISpaceTreeNode[], (node) => {
186→    createSpaceTreeNode(node, treeNodeMap);
187→    treeNodeMap[node.id] = node;
188→    spaceNodeMap[node.data.id] = node;
189→  });
190→  return {
191→    tree: tree as ISpaceTreeNode[],
192→    treeNodeMap,
193→    spaceNodeMap,
194→  };
195→}
