18→
19→    @Resource
20→    private ISpaceNodeStarService spaceNodeStarService;
21→
22→    @Resource
23→    private ISpaceNodeService spaceNodeService;
24→
25→    @Resource
26→    private SpaceNodeTransfer spaceNodeTransfer;
