import com.yottastudios.ns.collabspace.workspace.transfer.SpaceNodeTransfer;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeVo;
import jakarta.annotation.Resource;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class SpaceNodeStarUpdateManagerImpl implements SpaceNodeStarUpdateManager {

    @Resource
    private ISpaceNodeStarService spaceNodeStarService;

    @Resource
    private ISpaceNodeService spaceNodeService;

    @Resource
    private SpaceNodeTransfer spaceNodeTransfer;

    @Override
    @Transactional
    public SpaceNodeVo starSpaceNode(Long spaceNodeId, Long userId) {
        SpaceNodeEntity spaceNodeEntity = spaceNodeService.getById(spaceNodeId);
        ExceptionUtil.isNotNull(spaceNodeEntity, SpaceNodeException.NOT_EXIST);

        SpaceNodeStarEntity existStar = spaceNodeStarService.getByUserIdAndSpaceNodeId(userId, spaceNodeId);
        if (existStar == null) {
            SpaceNodeStarEntity newStar = SpaceNodeStarEntity.builder()
                    .spaceNodeId(spaceNodeId)
                    .userId(userId)
                    .build();
            spaceNodeStarService.save(newStar);
        }

        return spaceNodeTransfer.toSpaceNodeVo(spaceNodeEntity);
    }

    @Override
    @Transactional
    public SpaceNodeVo unstarSpaceNode(Long spaceNodeId, Long userId) {
        SpaceNodeEntity spaceNodeEntity = spaceNodeService.getById(spaceNodeId);
        ExceptionUtil.isNotNull(spaceNodeEntity, SpaceNodeException.NOT_EXIST);

        SpaceNodeStarEntity existStar = spaceNodeStarService.getByUserIdAndSpaceNodeId(userId, spaceNodeId);
        if (existStar != null) {
            spaceNodeStarService.removeById(existStar);
        }

        return spaceNodeTransfer.toSpaceNodeVo(spaceNodeEntity);
    }
}
