package com.yottastudios.ns.collabspace.workspace.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeTagEntity;
import com.yottastudios.ns.collabspace.workspace.mapper.SpaceNodeTagMapper;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeTagService;
import org.springframework.stereotype.Service;

import java.util.List;

@Service
public class ISpaceNodeTagServiceImpl extends ServiceImpl<SpaceNodeTagMapper, SpaceNodeTagEntity> implements ISpaceNodeTagService {

    @Override
    public List<SpaceNodeTagEntity> listBySpaceIdAndUserId(String spaceId, Long userId) {
        QueryWrapper<SpaceNodeTagEntity> qw = new QueryWrapper<>();
        qw.lambda()
                .eq(SpaceNodeTagEntity::getSpaceId, spaceId)
                .eq(SpaceNodeTagEntity::getUserId, userId)
                .orderByAsc(SpaceNodeTagEntity::getSortOrder)
                .orderByDesc(SpaceNodeTagEntity::getCreatedAt);
        return list(qw);
    }

    @Override
    public SpaceNodeTagEntity getBySpaceIdAndUserIdAndName(String spaceId, Long userId, String name) {
        QueryWrapper<SpaceNodeTagEntity> qw = new QueryWrapper<>();
        qw.lambda()
                .eq(SpaceNodeTagEntity::getSpaceId, spaceId)
                .eq(SpaceNodeTagEntity::getUserId, userId)
                .eq(SpaceNodeTagEntity::getName, name);
        return getOne(qw);
    }
}
