package com.yottastudios.ns.collabspace.workspace.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeTagRelEntity;
import com.yottastudios.ns.collabspace.workspace.mapper.SpaceNodeTagRelMapper;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeTagRelService;
import org.springframework.stereotype.Service;

import java.util.Collections;
import java.util.List;
import java.util.Set;

@Service
public class ISpaceNodeTagRelServiceImpl extends ServiceImpl<SpaceNodeTagRelMapper, SpaceNodeTagRelEntity> implements ISpaceNodeTagRelService {

    @Override
    public List<SpaceNodeTagRelEntity> listBySpaceNodeIdAndUserId(Long spaceNodeId, Long userId) {
        QueryWrapper<SpaceNodeTagRelEntity> qw = new QueryWrapper<>();
        qw.lambda()
                .eq(SpaceNodeTagRelEntity::getSpaceNodeId, spaceNodeId)
                .eq(SpaceNodeTagRelEntity::getUserId, userId);
        return list(qw);
    }

    @Override
    public List<SpaceNodeTagRelEntity> listBySpaceNodeIdsAndUserId(Set<Long> spaceNodeIds, Long userId) {
        if (spaceNodeIds == null || spaceNodeIds.isEmpty()) {
            return Collections.emptyList();
        }
        QueryWrapper<SpaceNodeTagRelEntity> qw = new QueryWrapper<>();
        qw.lambda()
                .in(SpaceNodeTagRelEntity::getSpaceNodeId, spaceNodeIds)
                .eq(SpaceNodeTagRelEntity::getUserId, userId);
        return list(qw);
    }

    @Override
    public List<SpaceNodeTagRelEntity> listByTagId(Long tagId) {
        QueryWrapper<SpaceNodeTagRelEntity> qw = new QueryWrapper<>();
        qw.lambda().eq(SpaceNodeTagRelEntity::getTagId, tagId);
        return list(qw);
    }

    @Override
    public SpaceNodeTagRelEntity getBySpaceNodeIdAndTagId(Long spaceNodeId, Long tagId) {
        QueryWrapper<SpaceNodeTagRelEntity> qw = new QueryWrapper<>();
        qw.lambda()
                .eq(SpaceNodeTagRelEntity::getSpaceNodeId, spaceNodeId)
                .eq(SpaceNodeTagRelEntity::getTagId, tagId);
        return getOne(qw);
    }

    @Override
    public List<Long> listSpaceNodeIdsByTagIdAndUserId(Long tagId, Long userId) {
        QueryWrapper<SpaceNodeTagRelEntity> qw = new QueryWrapper<>();
        qw.lambda()
                .eq(SpaceNodeTagRelEntity::getTagId, tagId)
                .eq(SpaceNodeTagRelEntity::getUserId, userId)
                .select(SpaceNodeTagRelEntity::getSpaceNodeId);
        return list(qw).stream().map(SpaceNodeTagRelEntity::getSpaceNodeId).toList();
    }
}
```

