package com.yottastudios.ns.collabspace.workspace.manager.update.impl;

import com.yottastudios.ns.collabspace.core.util.ExceptionUtil;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeTagEntity;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeTagRelEntity;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeException;
import com.yottastudios.ns.collabspace.workspace.manager.update.SpaceNodeTagUpdateManager;
import com.yottastudios.ns.collabspace.workspace.ro.BindTagRo;
import com.yottastudios.ns.collabspace.workspace.ro.CreateTagRo;
import com.yottastudios.ns.collabspace.workspace.ro.SetVisibilityTagRo;
import com.yottastudios.ns.collabspace.workspace.ro.UnbindTagRo;
import com.yottastudios.ns.collabspace.workspace.ro.UpdateTagRo;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeService;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeTagRelService;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeTagService;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeTagVo;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Slf4j
@Service
public class SpaceNodeTagUpdateManagerImpl implements SpaceNodeTagUpdateManager {

    @Resource
    private ISpaceNodeTagService spaceNodeTagService;

    @Resource
    private ISpaceNodeTagRelService spaceNodeTagRelService;

    @Resource
    private ISpaceNodeService spaceNodeService;

    @Override
    public SpaceNodeTagVo createTag(CreateTagRo ro, Long userId) {
        // 校验同空间同用户下标签名不重复
        SpaceNodeTagEntity existing = spaceNodeTagService.getBySpaceIdAndUserIdAndName(ro.getSpaceId(), userId, ro.getName());
        ExceptionUtil.isNull(existing, SpaceNodeException.TAG_NAME_DUPLICATE);

        SpaceNodeTagEntity entity = SpaceNodeTagEntity.builder()
                .spaceId(ro.getSpaceId())
                .name(ro.getName())
                .color(ro.getColor())
                .userId(userId)
                .sortOrder(0)
                .build();
        spaceNodeTagService.save(entity);

        log.info("[Tag] 创建个人标签, userId={}, spaceId={}, tagName={}", userId, ro.getSpaceId(), ro.getName());
        return toTagVo(entity);
    }

    @Override
    public SpaceNodeTagVo updateTag(Long tagId, UpdateTagRo ro, Long userId) {
        SpaceNodeTagEntity tag = spaceNodeTagService.getById(tagId);
        ExceptionUtil.isNotNull(tag, SpaceNodeException.TAG_NOT_EXIST);
        ExceptionUtil.isTrue(tag.getUserId().equals(userId), SpaceNodeException.TAG_NOT_OWNER);

        // 名称变更时校验不重复
        if (ro.getName() != null && !ro.getName().equals(tag.getName())) {
            SpaceNodeTagEntity existing = spaceNodeTagService.getBySpaceIdAndUserIdAndName(tag.getSpaceId(), userId, ro.getName());
            ExceptionUtil.isNull(existing, SpaceNodeException.TAG_NAME_DUPLICATE);
            tag.setName(ro.getName());
        }
        if (ro.getColor() != null) {
            tag.setColor(ro.getColor());
        }
        if (ro.getSortOrder() != null) {
            tag.setSortOrder(ro.getSortOrder());
        }
        spaceNodeTagService.updateById(tag);

        log.info("[Tag] 编辑个人标签, userId={}, tagId={}", userId, tagId);
        return toTagVo(tag);
    }

    @Override
    @Transactional
    public void deleteTag(Long tagId, Long userId) {
        SpaceNodeTagEntity tag = spaceNodeTagService.getById(tagId);
        ExceptionUtil.isNotNull(tag, SpaceNodeException.TAG_NOT_EXIST);
        ExceptionUtil.isTrue(tag.getUserId().equals(userId), SpaceNodeException.TAG_NOT_OWNER);

        // 级联逻辑删除所有关联记录
        List<SpaceNodeTagRelEntity> rels = spaceNodeTagRelService.listByTagId(tagId);
        if (!rels.isEmpty()) {
            spaceNodeTagRelService.removeByIds(rels.stream().map(SpaceNodeTagRelEntity::getId).toList());
        }
        spaceNodeTagService.removeById(tagId);

        log.info("[Tag] 删除个人标签, userId={}, tagId={}, 关联记录数={}", userId, tagId, rels.size());
    }

    @Override
    public void bindNode(BindTagRo ro, Long userId) {
        // 校验标签存在且归属当前用户
        SpaceNodeTagEntity tag = spaceNodeTagService.getById(ro.getTagId());
        ExceptionUtil.isNotNull(tag, SpaceNodeException.TAG_NOT_EXIST);
        ExceptionUtil.isTrue(tag.getUserId().equals(userId), SpaceNodeException.TAG_NOT_OWNER);

        // 校验文档存在
        SpaceNodeEntity node = spaceNodeService.getById(ro.getSpaceNodeId());
        ExceptionUtil.isNotNull(node, SpaceNodeException.NOT_EXIST);

        // 校验不重复绑定
        SpaceNodeTagRelEntity existRel = spaceNodeTagRelService.getBySpaceNodeIdAndTagId(ro.getSpaceNodeId(), ro.getTagId());
        ExceptionUtil.isNull(existRel, SpaceNodeException.TAG_ALREADY_BINDNODE);

        SpaceNodeTagRelEntity rel = SpaceNodeTagRelEntity.builder()
                .spaceNodeId(ro.getSpaceNodeId())
                .tagId(ro.getTagId())
                .userId(userId)
                .build();
        spaceNodeTagRelService.save(rel);

        log.info("[Tag] 绑定标签, userId={}, nodeId={}, tagId={}", userId, ro.getSpaceNodeId(), ro.getTagId());
    }

    @Override
    public void unbindNode(UnbindTagRo ro, Long userId) {
        SpaceNodeTagRelEntity rel = spaceNodeTagRelService.getBySpaceNodeIdAndTagId(ro.getSpaceNodeId(), ro.getTagId());
        ExceptionUtil.isNotNull(rel, SpaceNodeException.TAG_NOT_BINDNODE);
        ExceptionUtil.isTrue(rel.getUserId().equals(userId), SpaceNodeException.TAG_NOT_OWNER);

        spaceNodeTagRelService.removeById(rel.getId());

        log.info("[Tag] 解绑标签, userId={}, nodeId={}, tagId={}", userId, ro.getSpaceNodeId(), ro.getTagId());
    }

    @Override
    public void setVisibilityTag(SetVisibilityTagRo ro) {
        SpaceNodeEntity node = spaceNodeService.getById(ro.getSpaceNodeId());
        ExceptionUtil.isNotNull(node, SpaceNodeException.NOT_EXIST);

        node.setVisibilityTag(ro.getVisibilityTag());
        spaceNodeService.updateById(node);

        log.info("[Tag] 设置系统标签, nodeId={}, visibilityTag={}", ro.getSpaceNodeId(), ro.getVisibilityTag());
    }

    private SpaceNodeTagVo toTagVo(SpaceNodeTagEntity entity) {
        return SpaceNodeTagVo.builder()
                .id(entity.getId())
                .name(entity.getName())
                .color(entity.getColor())
                .sortOrder(entity.getSortOrder())
                .build();
    }
}
