                    .map(tag -> SpaceNodeTagVo.builder()
                            .id(tag.getId())
                            .name(tag.getName())
                            .color(tag.getColor())
                            .sortOrder(tag.getSortOrder())
                            .build())
                    .toList();
            vo.setTags(tagVos);
        }
    }
}
