 42→    public List<SpaceNodeVo> toSpaceNodeVo(List<SpaceNodeEntity> entities) {
 43→        if(CollectionUtils.isEmpty(entities)) return List.of();
 44→
 45→        long t0 = System.currentTimeMillis();
 46→
 47→        Long userId = UserHolder.get();
 48→        Set<Long> starredSpaceNodeSet = getStarredSpaceNodeSet(userId);
 49→        long t1 = System.currentTimeMillis();
 50→        log.info("[2009-perf][toSpaceNodeVo] getStarredSpaceNodeSet={}ms userId={}", t1 - t0, userId);
