@Slf4j
@RestController
@Tag(name = "SpaceNodeTag")
@ApiResource(path = "/node/tag")
public class SpaceNodeTagController {

    @Resource
    private SpaceNodeTagQueryManager spaceNodeTagQueryManager;

    @Resource
    private SpaceNodeTagUpdateManager spaceNodeTagUpdateManager;

    @PostResource(path = "/create", requiredPermission = false, externalOnly = true)
    @Operation(summary = "创建个人标签")
    public ResponseData<SpaceNodeTagVo> createTag(@RequestBody @Valid CreateTagRo ro) {
        Long userId = SessionContext.getUserId();
        SpaceNodeTagVo result = spaceNodeTagUpdateManager.createTag(ro, userId);
        return ResponseData.success(result);
    }

    @PostResource(path = "/{tagId}/update", requiredPermission = false, externalOnly = true)
    @Operation(summary = "编辑个人标签")
    public ResponseData<SpaceNodeTagVo> updateTag(@PathVariable Long tagId, @RequestBody @Valid UpdateTagRo ro) {
        Long userId = SessionContext.getUserId();
        SpaceNodeTagVo result = spaceNodeTagUpdateManager.updateTag(tagId, ro, userId);
        return ResponseData.success(result);
    }

    @PostResource(path = "/{tagId}/delete", requiredPermission = false, externalOnly = true)
    @Operation(summary = "删除个人标签")
    public ResponseData<Void> deleteTag(@PathVariable Long tagId) {
        Long userId = SessionContext.getUserId();
        spaceNodeTagUpdateManager.deleteTag(tagId, userId);
        return ResponseData.success();
    }

    @GetResource(path = "/list", requiredPermission = false)
    @Operation(summary = "获取我的标签列表")
    public ResponseData<List<SpaceNodeTagVo>> listTags(@RequestParam String spaceId) {
        Long userId = SessionContext.getUserId();
        List<SpaceNodeTagVo> result = spaceNodeTagQueryManager.listTags(spaceId, userId);
        return ResponseData.success(result);
    }

    @PostResource(path = "/bindNode", requiredPermission = false, externalOnly = true)
    @Operation(summary = "给文档贴标签")
    public ResponseData<Void> bindNode(@RequestBody @Valid BindTagRo ro) {
        Long userId = SessionContext.getUserId();
        spaceNodeTagUpdateManager.bindNode(ro, userId);
        return ResponseData.success();
    }

    @PostResource(path = "/unbindNode", requiredPermission = false, externalOnly = true)
    @Operation(summary = "取消文档标签")
    public ResponseData<Void> unbindNode(@RequestBody @Valid UnbindTagRo ro) {
        Long userId = SessionContext.getUserId();
        spaceNodeTagUpdateManager.unbindNode(ro, userId);
        return ResponseData.success();
    }

    @PostResource(path = "/queryNodes", requiredPermission = false)
    @Operation(summary = "按标签查文档列表")
    public ResponseData<IPage<SpaceNodeVo>> queryNodesByTag(@RequestBody @Valid TagNodeQueryRo ro) {
        Long userId = SessionContext.getUserId();
        IPage<SpaceNodeVo> result = spaceNodeTagQueryManager.queryNodesByTag(userId, ro);
        return ResponseData.success(result);
    }

    @PostResource(path = "/setVisibilityTag", requiredPermission = false, externalOnly = true)
    @Operation(summary = "设置文档系统标签（公开/私有）")
    public ResponseData<Void> setVisibilityTag(@RequestBody @Valid SetVisibilityTagRo ro) {
        spaceNodeTagUpdateManager.setVisibilityTag(ro);
        return ResponseData.success();
    }
}

