 37→    public SpaceNodeVo toSpaceNodeVo(SpaceNodeEntity entity) {
 38→        if (entity == null) return new SpaceNodeVo();
 39→        return toSpaceNodeVo(List.of(entity)).getFirst();
 40→    }
 41→
 42→    public List<SpaceNodeVo> toSpaceNodeVo(List<SpaceNodeEntity> entities) {
 43→        if(CollectionUtils.isEmpty(entities)) return List.of();
 44→
 45→        long t0 = System.currentTimeMillis();
 46→
 47→        Long userId = UserHolder.get();
 48→        Set<Long> starredSpaceNodeSet = getStarredSpaceNodeSet(userId);
 49→        long t1 = System.currentTimeMillis();
 50→        log.info("[2009-perf][toSpaceNodeVo] getStarredSpaceNodeSet={}ms userId={}", t1 - t0, userId);
 51→
 52→        List<String> spaceIds = entities.stream().map(SpaceNodeEntity::getSpaceId).toList().stream().distinct().toList();
 53→        List<SpaceAppRelEntity> spaceAppRelEntities = spaceAppRelService.listBySpaceIds(spaceIds);
 54→        long t2 = System.currentTimeMillis();
 55→        log.info("[2009-perf][toSpaceNodeVo] listBySpaceIds={}ms spaceCount={}", t2 - t1, spaceIds.size());
 56→
 57→        Map<String, Map<Integer, List<SpaceAppRelEntity>>> thirdAppGroupMap= spaceAppRelEntities.stream().collect(Collectors.groupingBy(SpaceAppRelEntity::getSpaceId, Collectors.groupingBy(SpaceAppRelEntity::getAppType)));
 58→
 59→        List<SpaceNodeVo> result = entities.stream()
 60→                .map(e -> {
 61→                    Boolean isStarred = starredSpaceNodeSet.contains(e.getId());
 62→                    String creatorName = userCacheService.getNicknameByUserId(e.getCreatedBy());
 63→                    String appSpaceId=e.getSpaceId();
 64→                    if(null!=thirdAppGroupMap.get(e.getSpaceId())){
 65→                        Map<Integer, List<SpaceAppRelEntity>> thirdAppMap = thirdAppGroupMap.get(e.getSpaceId());
 66→                        if(Objects.equals(e.getType(), SpaceNodeTypeEnum.AFFINE.getValue())
 67→                                &&CollectionUtils.isNotEmpty(thirdAppMap.get(SpaceAppTypeEnum.AFFINE.getValue())))
 68→                            appSpaceId=thirdAppMap.get(SpaceAppTypeEnum.AFFINE.getValue()).getFirst().getAppSpaceId();
 69→                    }
 70→                    return new SpaceNodeVo(e, creatorName, isStarred, appSpaceId, e.getIcon());
 71→                })
 72→                .toList();
 73→        long t3 = System.currentTimeMillis();
 74→        log.info("[2009-perf][toSpaceNodeVo] streamMapping(nicknames)={}ms entityCount={}", t3 - t2, entities.size());
 75→
 76→        return result;
 77→    }
