/**
 * 批量填充个人标签到 VO 列表。
 * 1. 收集所有节点 ID，批量查询当前用户的标签关联关系
 * 2. 若有关联，批量查询标签定义，按节点分组后写入各 VO
 */
private void enrichTags(List<SpaceNodeVo> vos, Long userId) {
    if (userId == null || CollectionUtils.isEmpty(vos)) return;

    Set<Long> nodeIds = vos.stream().map(SpaceNodeVo::getId).collect(Collectors.toSet());
    List<SpaceNodeTagRelEntity> relList = spaceNodeTagRelService.listBySpaceNodeIdsAndUserId(nodeIds, userId);
    if (CollectionUtils.isEmpty(relList)) return;

    // 批量取标签定义，并建立 tagId -> tag 的快速查找 Map
    Set<Long> tagIds = relList.stream().map(SpaceNodeTagRelEntity::getTagId).collect(Collectors.toSet());
    List<SpaceNodeTagEntity> tagEntities = spaceNodeTagService.listByIds(tagIds);
    Map<Long, SpaceNodeTagEntity> tagMap = tagEntities.stream()
            .collect(Collectors.toMap(SpaceNodeTagEntity::getId, t -> t));

    // 按 spaceNodeId 分组，将标签列表写入对应 VO
    Map<Long, List<SpaceNodeTagRelEntity>> relsByNodeId = relList.stream()
            .collect(Collectors.groupingBy(SpaceNodeTagRelEntity::getSpaceNodeId));

    for (SpaceNodeVo vo : vos) {
        List<SpaceNodeTagRelEntity> rels = relsByNodeId.get(vo.getId());
        if (CollectionUtils.isEmpty(rels)) continue;
        List<SpaceNodeTagVo> tagVos = rels.stream()
                .map(rel -> tagMap.get(rel.getTagId()))
                .filter(Objects::nonNull)
                .map(tag -> SpaceNodeTagVo.builder()
                        .id(tag.getId())
                        .name(tag.getName())
                        .color(tag.getColor())
                        .sortOrder(tag.getSortOrder())
                        .build())
                .collect(Collectors.toList());
        vo.setTags(tagVos);
    }
}

