package com.yottastudios.ns.collabspace.workspace.manager.query.impl;

import com.baomidou.mybatisplus.core.metadata.IPage;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeTagEntity;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeTagQueryManager;
import com.yottastudios.ns.collabspace.workspace.ro.TagNodeQueryRo;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeService;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeTagRelService;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeTagService;
import com.yottastudios.ns.collabspace.workspace.transfer.SpaceNodeTransfer;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeTagVo;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeVo;
import jakarta.annotation.Resource;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.function.Function;
import java.util.stream.Collectors;

@Service
public class SpaceNodeTagQueryManagerImpl implements SpaceNodeTagQueryManager {

    @Resource
    private ISpaceNodeTagService spaceNodeTagService;

    @Resource
    private ISpaceNodeTagRelService spaceNodeTagRelService;

    @Resource
    private ISpaceNodeService spaceNodeService;

    @Resource
    private SpaceNodeTransfer spaceNodeTransfer;

    @Override
    public List<SpaceNodeTagVo> listTags(String spaceId, Long userId) {
        List<SpaceNodeTagEntity> tags = spaceNodeTagService.listBySpaceIdAndUserId(spaceId, userId);
        return tags.stream().map(SpaceNodeTagVo::from).toList();
    }

    @Override
    public IPage<SpaceNodeVo> queryNodesByTag(Long userId, TagNodeQueryRo ro) {
        List<Long> spaceNodeIds = spaceNodeTagRelService.listSpaceNodeIdsByTagIdAndUserId(ro.getTagId(), userId);
        if (spaceNodeIds.isEmpty()) {
            return new Page<>(ro.getPageNum(), ro.getPageSize(), 0);
        }

        int total = spaceNodeIds.size();
        int fromIndex = (ro.getPageNum() - 1) * ro.getPageSize();
        if (fromIndex >= total) {
            return new Page<>(ro.getPageNum(), ro.getPageSize(), total);
        }
        int toIndex = Math.min(fromIndex + ro.getPageSize(), total);
        List<Long> pagedIds = spaceNodeIds.subList(fromIndex, toIndex);

        List<SpaceNodeEntity> entities = spaceNodeService.listByIds(pagedIds);
        // 保持 tagId 排序顺序（listSpaceNodeIdsByTagIdAndUserId 返回的顺序）
        Map<Long, SpaceNodeEntity> entityMap = entities.stream()
                .collect(Collectors.toMap(SpaceNodeEntity::getId, Function.identity()));
        List<SpaceNodeEntity> sorted = pagedIds.stream()
                .map(entityMap::get)
                .filter(Objects::nonNull)
                .toList();

        List<SpaceNodeVo> vos = spaceNodeTransfer.toSpaceNodeVoWithRole(sorted);
        Page<SpaceNodeVo> page = new Page<>(ro.getPageNum(), ro.getPageSize(), total);
        page.setRecords(vos);
        return page;
    }

    private SpaceNodeTagVo toTagVo(SpaceNodeTagEntity entity) {
        return SpaceNodeTagVo.builder()
                .id(entity.getId())
                .name(entity.getName())
                .color(entity.getColor())
                .sortOrder(entity.getSortOrder())
                .build();
    }
}

package com.yottastudios.ns.collabspace.workspace.transfer;

import com.yottastudios.ns.collabspace.shared.cache.service.UserCacheService;
import com.yottastudios.ns.collabspace.shared.holder.UserHolder;
import com.yottastudios.ns.collabspace.space.entity.SpaceAppRelEntity;
import com.yottastudios.ns.collabspace.space.enums.SpaceAppTypeEnum;
import com.yottastudios.ns.collabspace.space.service.ISpaceAppRelService;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeStarEntity;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeTagEntity;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeTagRelEntity;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeTypeEnum;
import com.yottastudios.ns.collabspace.workspace.filter.NodeRoleFilter;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeStarService;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeTagRelService;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeTagService;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeTagVo;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeVo;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.stereotype.Service;

import java.util.*;
import java.util.stream.Collectors;

@Slf4j
@Service
public class SpaceNodeTransfer {
    @Resource
    private UserCacheService userCacheService;

    @Resource
    private ISpaceNodeStarService spaceNodeStarService;

    @Resource
    private ISpaceAppRelService spaceAppRelService;

    @Resource
    private NodeRoleFilter nodeRoleFilter;

    @Resource
    private ISpaceNodeTagRelService spaceNodeTagRelService;

    @Resource
    private ISpaceNodeTagService spaceNodeTagService;

    public SpaceNodeVo toSpaceNodeVo(SpaceNodeEntity entity) {
        if (entity == null) return new SpaceNodeVo();
        return toSpaceNodeVo(List.of(entity)).getFirst();
    }

    public List<SpaceNodeVo> toSpaceNodeVo(List<SpaceNodeEntity> entities) {
        if(CollectionUtils.isEmpty(entities)) return List.of();

        long t0 = System.currentTimeMillis();

        Long userId = UserHolder.get();
        Set<Long> starredSpaceNodeSet = getStarredSpaceNodeSet(userId);
        long t1 = System.currentTimeMillis();
        log.info("[2009-perf][toSpaceNodeVo] getStarredSpaceNodeSet={}ms userId={}", t1 - t0, userId);

        List<String> spaceIds = entities.stream().map(SpaceNodeEntity::getSpaceId).toList().stream().distinct().toList();
        List<SpaceAppRelEntity> spaceAppRelEntities = spaceAppRelService.listBySpaceIds(spaceIds);
        long t2 = System.currentTimeMillis();
        log.info("[2009-perf][toSpaceNodeVo] listBySpaceIds={}ms spaceCount={}", t2 - t1, spaceIds.size());

        Map<String, Map<Integer, List<SpaceAppRelEntity>>> thirdAppGroupMap= spaceAppRelEntities.stream().collect(Collectors.groupingBy(SpaceAppRelEntity::getSpaceId, Collectors.groupingBy(SpaceAppRelEntity::getAppType)));

        List<SpaceNodeVo> result = entities.stream()
                .map(e -> {
                    Boolean isStarred = starredSpaceNodeSet.contains(e.getId());
                    String creatorName = userCacheService.getNicknameByUserId(e.getCreatedBy());
                    String appSpaceId=e.getSpaceId();
                    if(null!=thirdAppGroupMap.get(e.getSpaceId())){
                        Map<Integer, List<SpaceAppRelEntity>> thirdAppMap = thirdAppGroupMap.get(e.getSpaceId());
                        if(Objects.equals(e.getType(), SpaceNodeTypeEnum.AFFINE.getValue())
                                &&CollectionUtils.isNotEmpty(thirdAppMap.get(SpaceAppTypeEnum.AFFINE.getValue())))
                            appSpaceId=thirdAppMap.get(SpaceAppTypeEnum.AFFINE.getValue()).getFirst().getAppSpaceId();
                    }
                    return new SpaceNodeVo(e, creatorName, isStarred, appSpaceId, e.getIcon());
                })
                .toList();
        long t3 = System.currentTimeMillis();
        log.info("[2009-perf][toSpaceNodeVo] streamMapping(nicknames)={}ms entityCount={}", t3 - t2, entities.size());

        // 填充个人标签：查询当前用户在这批节点上的标签关系，再批量获取标签定义
        enrichTags(result, userId);
        long t4 = System.currentTimeMillis();
        log.info("[2009-perf][toSpaceNodeVo] enrichTags={}ms userId={}", t4 - t3, userId);

        return result;
    }

    public List<SpaceNodeVo> toSpaceNodeVoWithRole(List<SpaceNodeEntity> entities) {
        List<SpaceNodeVo> vos = toSpaceNodeVo(entities);
        return nodeRoleFilter.filterAndSetRole(vos);
    }

    public SpaceNodeVo toSpaceNodeVoWithRole(SpaceNodeEntity entity) {
        if (entity == null) return new SpaceNodeVo();
        SpaceNodeVo vo = toSpaceNodeVo(entity);
        List<SpaceNodeVo> vos = nodeRoleFilter.filterAndSetRole(List.of(vo));
        return CollectionUtils.isNotEmpty(vos) ? vos.getFirst() : new SpaceNodeVo();
    }

    private Set<Long> getStarredSpaceNodeSet(Long userId) {
        if(userId == null) return new HashSet<>();
        List<SpaceNodeStarEntity> starEntities = spaceNodeStarService.getByUserId(userId);
        if (CollectionUtils.isEmpty(starEntities)) return new HashSet<>();
        return starEntities.stream().map(SpaceNodeStarEntity::getSpaceNodeId).collect(Collectors.toSet());
    }

    /**
     * 批量填充个人标签到 VO 列表。
     * 1. 收集所有节点 ID，批量查询当前用户的标签关联关系
     * 2. 若有关联，批量查询标签定义，按节点分组后写入各 VO
     */
    private void enrichTags(List<SpaceNodeVo> vos, Long userId) {
        if (userId == null || CollectionUtils.isEmpty(vos)) return;

        Set<Long> nodeIds = vos.stream().map(SpaceNodeVo::getId).collect(Collectors.toSet());
        List<SpaceNodeTagRelEntity> relList = spaceNodeTagRelService.listBySpaceNodeIdsAndUserId(nodeIds, userId);
        if (CollectionUtils.isEmpty(relList)) return;

        // 批量取标签定义，并建立 tagId -> tag 的快速查找 Map
        Set<Long> tagIds = relList.stream().map(SpaceNodeTagRelEntity::getTagId).collect(Collectors.toSet());
        List<SpaceNodeTagEntity> tagEntities = spaceNodeTagService.listByIds(tagIds);
        Map<Long, SpaceNodeTagEntity> tagMap = tagEntities.stream()
                .collect(Collectors.toMap(SpaceNodeTagEntity::getId, t -> t));

        // 按 spaceNodeId 分组，将标签列表写入对应 VO
        Map<Long, List<SpaceNodeTagRelEntity>> relsByNodeId = relList.stream()
                .collect(Collectors.groupingBy(SpaceNodeTagRelEntity::getSpaceNodeId));

        for (SpaceNodeVo vo : vos) {
            List<SpaceNodeTagRelEntity> rels = relsByNodeId.get(vo.getId());
            if (CollectionUtils.isEmpty(rels)) continue;
            List<SpaceNodeTagVo> tagVos = rels.stream()
                    .map(rel -> tagMap.get(rel.getTagId()))
                    .filter(Objects::nonNull)
                    .map(tag -> SpaceNodeTagVo.builder()
                            .id(tag.getId())
                            .name(tag.getName())
                            .color(tag.getColor())
                            .sortOrder(tag.getSortOrder())
                            .build())
                    .collect(Collectors.toList());
            vo.setTags(tagVos);
        }
    }

    public List<SpaceNodeVo> toSpaceNodeOnlyInAio(List<SpaceNodeEntity> entities) {
        if(CollectionUtils.isEmpty(entities)) return List.of();
        return entities.stream()
                .map(e -> new SpaceNodeVo(e, null, null, null, e.getIcon()))
                .toList();
    }

}

