/**
 * [文档标签] - 接口测试脚本
 *
 * 用法: node 05-test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 自动登录测试环境，无需手动填 Cookie
 *
 * 功能点覆盖（来自 03-后端功能点对照.md）：
 *   §1. 创建个人标签（校验重名后保存）
 *   §2. 标签名去重（同空间同用户下唯一）
 *   §3. 编辑个人标签（可改名/颜色/排序）
 *   §4. 编辑时去重（改名时校验不与已有冲突）
 *   §5. 删除个人标签（级联删除关联记录）
 *   §6. 查询标签列表（按 sortOrder 升序）
 *   §7. 给文档贴标签（校验标签/文档/不重复）
 *   §8. 防重复绑定（已绑定则报错）
 *   §9. 取消文档标签（验证归属后逻辑删除）
 *   §10. 设置系统标签（更新 visibility_tag 字段）
 *   §11. 系统标签枚举（0=无, 1=公开, 2=私有）
 *   §12. 按标签查文档（分页）
 *   §13. 个人标签归属校验（操作前验证 userId）
 *   §14. 仅本人可见（查询条件限定用户）
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
  loginEmail: 'luobeilin@yottastudios.com',
  normalEmail: 'nanbei2@yottastudios.com',
  spaceId: 'spcf46VuYUur9',
  spaceNodeId: '1933447481411833900',   // 一个已存在的文档节点
  spaceNodeId2: '1933447481453777000',  // 第二个文档节点
};

const API_PREFIX = '/api/v1/node/tag';

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';
let xsrfToken = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========

function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const [k, v] = kv.split('=');
    cookies[k.trim()] = v.trim();
  }
  return cookies;
}

async function rawFetch(method, url, body) {
  const headers = {
    'content-type': 'application/json',
  };
  if (cookie) headers['cookie'] = cookie;
  if (xsrfToken) headers['x-xsrf-token'] = xsrfToken;

  const opts = { method, headers, redirect: 'manual' };
  if (body) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  return res.json();
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
  return res.json();
}

// ========== 登录管理 ==========

async function login() {
  console.log(`🔑 登录 ${CONFIG.loginEmail} ...`);
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.loginEmail}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log('❌ 登录失败');
    process.exit(1);
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  console.log(`   ✅ 登录成功\n`);
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = { cookie, xsrfToken };
}
function restoreSession(name) {
  ({ cookie, xsrfToken } = savedSessions[name]);
}

async function loginAs(email) {
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${email}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log(`  ⚠️  登录 ${email} 失败，跳过`);
    return false;
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  return true;
}

// ========== 全局变量：测试过程中创建的资源 ID ==========
let createdTagId = null;
let createdTagId2 = null;

// ========== 测试用例 ==========

// §1 创建个人标签 + §2 标签名去重
async function test_1_2_create_tag() {
  console.log('\n📋 §1.创建个人标签 + §2.标签名去重');

  // §1 正常创建
  const ts = Date.now();
  const tagName = `测试标签_${ts}`;
  const res = await POST(`${API_PREFIX}/create`, {
    spaceId: CONFIG.spaceId,
    name: tagName,
    color: '#FF5733',
  });
  assert('§1.创建个人标签 - 返回 success', res.success === true, res);
  assert('§1.创建个人标签 - data 不为 null', res.data != null, res.data);
  assert('§1.创建个人标签 - 返回 id', res.data?.id != null, res.data?.id);
  assert('§1.创建个人标签 - 返回 name 正确', res.data?.name === tagName, res.data?.name);
  assert('§1.创建个人标签 - 返回 color 正确', res.data?.color === '#FF5733', res.data?.color);
  assert('§1.创建个人标签 - 返回 sortOrder', res.data?.sortOrder != null, res.data?.sortOrder);

  if (res.data?.id) {
    createdTagId = String(res.data.id);
  }

  // §2 重名检测
  const dupRes = await POST(`${API_PREFIX}/create`, {
    spaceId: CONFIG.spaceId,
    name: tagName,
    color: '#00FF00',
  });
  assert('§2.标签名去重 - 重复名称返回 success=false', dupRes.success === false, dupRes);
  assert('§2.标签名去重 - 错误码非500', dupRes.code !== 500, dupRes.code);

  // 创建第二个标签用于后续测试
  const tagName2 = `测试标签2_${ts}`;
  const res2 = await POST(`${API_PREFIX}/create`, {
    spaceId: CONFIG.spaceId,
    name: tagName2,
    color: '#33FF57',
  });
  if (res2.data?.id) {
    createdTagId2 = String(res2.data.id);
  }
}

// §3 编辑个人标签 + §4 编辑时去重
async function test_3_4_update_tag() {
  console.log('\n📋 §3.编辑个人标签 + §4.编辑时去重');
  if (!createdTagId) { console.log('  ⚠️ 无标签ID，跳过'); return; }

  // §3 改颜色
  const res1 = await POST(`${API_PREFIX}/${createdTagId}/update`, {
    color: '#0000FF',
  });
  assert('§3.编辑个人标签 - 改颜色返回 success', res1.success === true, res1);
  assert('§3.编辑个人标签 - 颜色已更新', res1.data?.color === '#0000FF', res1.data?.color);

  // §3 改排序
  const res2 = await POST(`${API_PREFIX}/${createdTagId}/update`, {
    sortOrder: 10,
  });
  assert('§3.编辑个人标签 - 改排序返回 success', res2.success === true, res2);
  assert('§3.编辑个人标签 - 排序已更新', res2.data?.sortOrder === 10, res2.data?.sortOrder);

  // §3 改名称
  const newName = `已编辑标签_${Date.now()}`;
  const res3 = await POST(`${API_PREFIX}/${createdTagId}/update`, {
    name: newName,
  });
  assert('§3.编辑个人标签 - 改名返回 success', res3.success === true, res3);
  assert('§3.编辑个人标签 - 名称已更新', res3.data?.name === newName, res3.data?.name);

  // §4 改名为已存在的标签名（createdTagId2 的名称）
  if (createdTagId2) {
    // 先获取第二个标签的名称
    const listRes = await GET(`${API_PREFIX}/list?spaceId=${CONFIG.spaceId}`);
    const tag2 = listRes.data?.find(t => String(t.id) === createdTagId2);
    if (tag2) {
      const dupRes = await POST(`${API_PREFIX}/${createdTagId}/update`, {
        name: tag2.name,
      });
      assert('§4.编辑时去重 - 改名为已有名称返回 success=false', dupRes.success === false, dupRes);
      assert('§4.编辑时去重 - 错误码非500', dupRes.code !== 500, dupRes.code);
    }
  }
}

// §6 查询标签列表 + §14 仅本人可见
async function test_6_14_list_tags() {
  console.log('\n📋 §6.查询标签列表 + §14.仅本人可见');

  const res = await GET(`${API_PREFIX}/list?spaceId=${CONFIG.spaceId}`);
  assert('§6.查询标签列表 - 返回 success', res.success === true, res);
  assert('§6.查询标签列表 - data 是数组', Array.isArray(res.data), res.data);
  assert('§6.查询标签列表 - 至少有创建的标签', res.data?.length >= 1, res.data?.length);

  if (res.data?.length > 0) {
    const first = res.data[0];
    assert('§6.查询标签列表 - 记录含 id', first.id != null, first.id);
    assert('§6.查询标签列表 - 记录含 name (string)', typeof first.name === 'string', first.name);
    assert('§6.查询标签列表 - 记录含 color (string)', typeof first.color === 'string', first.color);
    assert('§6.查询标签列表 - 记录含 sortOrder', first.sortOrder != null, first.sortOrder);
  }

  // §6 验证排序：sortOrder 应为升序
  if (res.data?.length > 1) {
    const sorted = res.data.every((t, i) => i === 0 || t.sortOrder >= res.data[i - 1].sortOrder);
    assert('§6.查询标签列表 - 按 sortOrder 升序排列', sorted);
  }

  // §14 仅本人可见：切换到另一个用户
  saveSession('admin');
  if (await loginAs(CONFIG.normalEmail)) {
    const otherRes = await GET(`${API_PREFIX}/list?spaceId=${CONFIG.spaceId}`);
    assert('§14.仅本人可见 - 其他用户返回 success', otherRes.success === true, otherRes);
    // 其他用户不应看到我的标签
    if (otherRes.data && createdTagId) {
      const found = otherRes.data.find(t => String(t.id) === createdTagId);
      assert('§14.仅本人可见 - 其他用户看不到我的标签', found == null);
    }
  }
  restoreSession('admin');
}

// §7 给文档贴标签 + §8 防重复绑定
async function test_7_8_bind_node() {
  console.log('\n📋 §7.给文档贴标签 + §8.防重复绑定');
  if (!createdTagId) { console.log('  ⚠️ 无标签ID，跳过'); return; }

  // §7 正常绑定
  const res = await POST(`${API_PREFIX}/bindNode`, {
    spaceNodeId: CONFIG.spaceNodeId,
    tagId: createdTagId,
  });
  assert('§7.给文档贴标签 - 返回 success', res.success === true, res);
  assert('§7.给文档贴标签 - data 为 null (Void)', res.data == null, res.data);

  // §8 重复绑定
  const dupRes = await POST(`${API_PREFIX}/bindNode`, {
    spaceNodeId: CONFIG.spaceNodeId,
    tagId: createdTagId,
  });
  assert('§8.防重复绑定 - 重复绑定返回 success=false', dupRes.success === false, dupRes);
  assert('§8.防重复绑定 - 错误码非500', dupRes.code !== 500, dupRes.code);

  // 给第二个节点也绑定，用于后续查询测试
  if (createdTagId) {
    await POST(`${API_PREFIX}/bindNode`, {
      spaceNodeId: CONFIG.spaceNodeId2,
      tagId: createdTagId,
    });
  }
}

// §12 按标签查文档（分页）
async function test_12_query_nodes() {
  console.log('\n📋 §12.按标签查文档（分页）');
  if (!createdTagId) { console.log('  ⚠️ 无标签ID，跳过'); return; }

  const res = await POST(`${API_PREFIX}/queryNodes`, {
    tagId: createdTagId,
    pageNum: 1,
    pageSize: 25,
  });
  assert('§12.按标签查文档 - 返回 success', res.success === true, res);
  assert('§12.按标签查文档 - data 不为 null', res.data != null, res.data);
  assert('§12.按标签查文档 - 有 records 数组', Array.isArray(res.data?.records), res.data?.records);
  assert('§12.按标签查文档 - total >= 1', res.data?.total >= 1, res.data?.total);
  assert('§12.按标签查文档 - records 有数据', res.data?.records?.length >= 1, res.data?.records?.length);

  // 分页：pageSize=1
  const p1 = await POST(`${API_PREFIX}/queryNodes`, {
    tagId: createdTagId,
    pageNum: 1,
    pageSize: 1,
  });
  assert('§12.分页 - pageSize=1 最多返回1条', p1.data?.records?.length <= 1, p1.data?.records?.length);
  assert('§12.分页 - total 不变', p1.data?.total === res.data?.total, p1.data?.total);

  // 超出最后一页
  const overPage = await POST(`${API_PREFIX}/queryNodes`, {
    tagId: createdTagId,
    pageNum: 9999,
    pageSize: 25,
  });
  assert('§12.分页 - 超页返回空列表', overPage.data?.records?.length === 0, overPage.data?.records?.length);
}

// §9 取消文档标签
async function test_9_unbind_node() {
  console.log('\n📋 §9.取消文档标签');
  if (!createdTagId) { console.log('  ⚠️ 无标签ID，跳过'); return; }

  // 先解绑第二个节点
  const res = await POST(`${API_PREFIX}/unbindNode`, {
    spaceNodeId: CONFIG.spaceNodeId2,
    tagId: createdTagId,
  });
  assert('§9.取消文档标签 - 返回 success', res.success === true, res);
  assert('§9.取消文档标签 - data 为 null (Void)', res.data == null, res.data);

  // 再次解绑应失败（已解绑）
  const dupRes = await POST(`${API_PREFIX}/unbindNode`, {
    spaceNodeId: CONFIG.spaceNodeId2,
    tagId: createdTagId,
  });
  assert('§9.取消文档标签 - 已解绑再解绑返回 success=false', dupRes.success === false, dupRes);
  assert('§9.取消文档标签 - 错误码非500', dupRes.code !== 500, dupRes.code);
}

// §10 设置系统标签 + §11 系统标签枚举
async function test_10_11_set_visibility_tag() {
  console.log('\n📋 §10.设置系统标签 + §11.系统标签枚举');

  // §10 设置为公开(1)
  const res1 = await POST(`${API_PREFIX}/setVisibilityTag`, {
    spaceNodeId: CONFIG.spaceNodeId,
    visibilityTag: 1,
  });
  assert('§10.设置系统标签 - 设为公开返回 success', res1.success === true, res1);
  assert('§10.设置系统标签 - data 为 null (Void)', res1.data == null, res1.data);

  // §11 设置为私有(2)
  const res2 = await POST(`${API_PREFIX}/setVisibilityTag`, {
    spaceNodeId: CONFIG.spaceNodeId,
    visibilityTag: 2,
  });
  assert('§11.系统标签枚举 - 设为私有返回 success', res2.success === true, res2);

  // §11 清除(0)
  const res3 = await POST(`${API_PREFIX}/setVisibilityTag`, {
    spaceNodeId: CONFIG.spaceNodeId,
    visibilityTag: 0,
  });
  assert('§11.系统标签枚举 - 清除返回 success', res3.success === true, res3);

  // §11 超出枚举范围
  const badRes = await POST(`${API_PREFIX}/setVisibilityTag`, {
    spaceNodeId: CONFIG.spaceNodeId,
    visibilityTag: 3,
  });
  assert('§11.系统标签枚举 - visibilityTag=3 返回 success=false', badRes.success === false, badRes);
  assert('§11.系统标签枚举 - 非法值错误码非500', badRes.code !== 500, badRes.code);

  const badRes2 = await POST(`${API_PREFIX}/setVisibilityTag`, {
    spaceNodeId: CONFIG.spaceNodeId,
    visibilityTag: -1,
  });
  assert('§11.系统标签枚举 - visibilityTag=-1 返回 success=false', badRes2.success === false, badRes2);
}

// §13 个人标签归属校验（多账号写权限）
async function test_13_tag_ownership() {
  console.log('\n📋 §13.个人标签归属校验（多账号）');
  if (!createdTagId) { console.log('  ⚠️ 无标签ID，跳过'); return; }

  saveSession('admin');

  if (await loginAs(CONFIG.normalEmail)) {
    // 其他用户尝试编辑我的标签
    const editRes = await POST(`${API_PREFIX}/${createdTagId}/update`, {
      name: '被篡改的标签名',
    });
    assert('§13.归属校验 - 其他用户编辑我的标签被拒绝', editRes.success === false, editRes);
    assert('§13.归属校验 - 编辑拒绝错误码非500', editRes.code !== 500, editRes.code);

    // 其他用户尝试删除我的标签
    const delRes = await POST(`${API_PREFIX}/${createdTagId}/delete`);
    assert('§13.归属校验 - 其他用户删除我的标签被拒绝', delRes.success === false, delRes);
    assert('§13.归属校验 - 删除拒绝错误码非500', delRes.code !== 500, delRes.code);

    // 其他用户尝试用我的标签绑定文档
    const bindRes = await POST(`${API_PREFIX}/bindNode`, {
      spaceNodeId: CONFIG.spaceNodeId2,
      tagId: createdTagId,
    });
    assert('§13.归属校验 - 其他用户用我的标签绑定被拒绝', bindRes.success === false, bindRes);
    assert('§13.归属校验 - 绑定拒绝错误码非500', bindRes.code !== 500, bindRes.code);
  }

  restoreSession('admin');
}

// §5 删除个人标签（级联删除关联记录）
async function test_5_delete_tag() {
  console.log('\n📋 §5.删除个人标签（级联删除）');
