// ========== 维度12：数据重复检测 ==========
async function test_duplicate_data() {
  console.log('\n🐛 维度12：数据重复检测');

  const ts = Date.now();
  const tagName = `重复测试_${ts}`;

  // 1. 创建标签
  const createRes = await POST(`${API_PREFIX}/create`, {
    spaceId: CONFIG.spaceId,
    name: tagName,
    color: '#111111',
  });
  assert('重复检测 - 创建标签成功', createRes.success === true, createRes);
  const tagId = createRes.data?.id ? String(createRes.data.id) : null;
  if (!tagId) return;

  // 2. 绑定文档
  await POST(`${API_PREFIX}/bindNode`, { spaceNodeId: CONFIG.spaceNodeId, tagId });

  // 3. 再次绑定同一文档（应拒绝）
  const dupBind = await POST(`${API_PREFIX}/bindNode`, { spaceNodeId: CONFIG.spaceNodeId, tagId });
  assert('重复检测 - 重复绑定被拒绝', dupBind.success === false);

  // 4. 查询验证只有一条记录
  const queryRes = await POST(`${API_PREFIX}/queryNodes`, { tagId, pageNum: 1, pageSize: 25 });
  const matchCount = queryRes.data?.records?.filter(r => String(r.id) === CONFIG.spaceNodeId).length || 0;
  assert('重复检测 - 绑定后查询只出现1次', matchCount <= 1, matchCount);

  // 5. 清理
  await POST(`${API_PREFIX}/unbindNode`, { spaceNodeId: CONFIG.spaceNodeId, tagId });
  await POST(`${API_PREFIX}/${tagId}/delete`);
}

