    const tmpTagId = String(tmpRes.data.id);
    const r5 = await POST(`${API_PREFIX}/bindNode`, { spaceNodeId: fakeNodeId, tagId: tmpTagId });
    assert('不存在 - bindNode 不存在的节点 success=false', r5.success === false, r5);
    assert('不存在 - bindNode 不存在的节点 错误码非500', r5.code !== 500, r5.code);

    // setVisibilityTag 不存在的节点
    const r6 = await POST(`${API_PREFIX}/setVisibilityTag`, { spaceNodeId: fakeNodeId, visibilityTag: 1 });
    assert('不存在 - setVisibilityTag 不存在的节点 success=false', r6.success === false, r6);
    assert('不存在 - setVisibilityTag 不存在的节点 错误码非500', r6.code !== 500, r6.code);

    // 清理临时标签
    await POST(`${API_PREFIX}/${tmpTagId}/delete`);
  }
}

// ========== 维度9：并发请求 ==========
async function test_concurrency() {
  console.log('\n🔀 维度9：并发请求');

  const promises = Array.from({ length: 5 }, () =>
    GET(`${API_PREFIX}/list?spaceId=${CONFIG.spaceId}`)
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.success === true);
  assert('并发 - 5个并发 list 请求都成功', allOk);

  // 并发创建不同名称的标签
  const ts = Date.now();
  const createPromises = Array.from({ length: 3 }, (_, i) =>
    POST(`${API_PREFIX}/create`, {
      spaceId: CONFIG.spaceId,
      name: `并发标签${i}_${ts}`,
      color: '#' + String(i).repeat(6).slice(0, 6),
    })
  );
  const createResults = await Promise.all(createPromises);
  const allCreated = createResults.every(r => r.success === true);
  assert('并发 - 3个并发 create 请求都成功', allCreated);

  // 清理
  for (const r of createResults) {
    if (r.data?.id) {
      await POST(`${API_PREFIX}/${String(r.data.id)}/delete`);
    }
  }
}

// ========== 维度10：响应结构一致性 ==========
async function test_response_structure() {
  console.log('\n📦 维度10：响应结构一致性');

  // list 接口 - 返回 List<SpaceNodeTagVo>
  const listRes = await GET(`${API_PREFIX}/list?spaceId=${CONFIG.spaceId}`);
  assert('响应结构 - list 有 success 字段', typeof listRes.success === 'boolean', listRes.success);
  assert('响应结构 - list 有 code 字段', listRes.code != null, listRes.code);
  assert('响应结构 - list data 是数组', Array.isArray(listRes.data), listRes.data);

  // queryNodes 接口 - 返回 IPage<SpaceNodeVo>
  // 先创建临时标签
  const tmpTag = await POST(`${API_PREFIX}/create`, {
    spaceId: CONFIG.spaceId,
    name: `结构测试_${Date.now()}`,
    color: '#ABCDEF',
  });
  if (tmpTag.data?.id) {
    const tmpTagId = String(tmpTag.data.id);
    const queryRes = await POST(`${API_PREFIX}/queryNodes`, {
      tagId: tmpTagId,
      pageNum: 1,
      pageSize: 10,
    });
    assert('响应结构 - queryNodes 有 success 字段', typeof queryRes.success === 'boolean');
    if (queryRes.success && queryRes.data) {
      assert('响应结构 - queryNodes 有 records', Array.isArray(queryRes.data.records));
      assert('响应结构 - queryNodes 有 total', typeof queryRes.data.total === 'number', queryRes.data.total);
    }
    // 清理
    await POST(`${API_PREFIX}/${tmpTagId}/delete`);
  }
}

// ========== 维度12：数据重复检测 ==========
async function test_duplicate_data() {
  console.log('\n🐛 维度12：数据重复检测');

  const ts = Date.now();
  const tagName = `重复测试_${ts}`;

  // 1. 创建标签
  const createRes = await POST(`${API_PREFIX}/create`, {
    spaceId: CONFIG.spaceId,
    name: tagName,
    color: '#111111',
  });
  assert('重复检测 - 创建标签成功', createRes.success === true, createRes);
  const tagId = createRes.data?.id ? String(createRes.data.id) : null;
  if (!tagId) return;

  // 2. 绑定文档
  await POST(`${API_PREFIX}/bindNode`, { spaceNodeId: CONFIG.spaceNodeId, tagId });

  // 3. 再次绑定同一文档（应拒绝）
  const dupBind = await POST(`${API_PREFIX}/bindNode`, { spaceNodeId: CONFIG.spaceNodeId, tagId });
  assert('重复检测 - 重复绑定被拒绝', dupBind.success === false);

  // 4. 查询验证只有一条记录
  const queryRes = await POST(`${API_PREFIX}/queryNodes`, { tagId, pageNum: 1, pageSize: 25 });
  const matchCount = queryRes.data?.records?.filter(r => String(r.id) === CONFIG.spaceNodeId).length || 0;
  assert('重复检测 - 绑定后查询只出现1次', matchCount <= 1, matchCount);

  // 5. 清理
  await POST(`${API_PREFIX}/unbindNode`, { spaceNodeId: CONFIG.spaceNodeId, tagId });
  await POST(`${API_PREFIX}/${tagId}/delete`);
}

// ========== 维度13：错误码规范性 ==========
async function test_error_code_standard() {
  console.log('\n🔢 维度13：错误码规范性');

  // 权限不足：其他用户操作我的标签
  // 先创建一个标签
  const tmpTag = await POST(`${API_PREFIX}/create`, {
    spaceId: CONFIG.spaceId,
    name: `错误码测试_${Date.now()}`,
    color: '#222222',
  });
  const tmpTagId = tmpTag.data?.id ? String(tmpTag.data.id) : null;
  if (!tmpTagId) return;

  saveSession('admin');
  if (await loginAs(CONFIG.normalEmail)) {
    const r1 = await POST(`${API_PREFIX}/${tmpTagId}/update`, { name: '篡改' });
    assert('错误码 - 权限不足 success=false', r1.success === false);
    assert('错误码 - 权限不足不返回500', r1.code !== 500, r1.code);

    const r2 = await POST(`${API_PREFIX}/${tmpTagId}/delete`);
    assert('错误码 - 权限不足删除不返回500', r2.code !== 500, r2.code);
  }
  restoreSession('admin');

  // 业务异常：不存在的标签
  const r3 = await POST(`${API_PREFIX}/1/update`, { name: '不存在' });
  assert('错误码 - 标签不存在不返回500', r3.code !== 500, r3.code);

  // 参数校验异常
  const r4 = await POST(`${API_PREFIX}/create`, {});
  assert('错误码 - 参数校验不返回500', r4.code !== 500, r4.code);

  // 清理
  await POST(`${API_PREFIX}/${tmpTagId}/delete`);
}

// ========== 维度7补充：未登录访问 ==========
async function test_unauthenticated() {
  console.log('\n🔒 未登录访问');
  saveSession('admin');
  cookie = ''; xsrfToken = '';

  // GET 接口（list 没有 externalOnly，可能不强制登录）
  const getRes = await rawFetch('GET', `${CONFIG.host}/api/v1${API_PREFIX}/list?spaceId=${CONFIG.spaceId}`);
  assert('未登录 - GET list 不报500', getRes.status !== 500, getRes.status);

  // POST 写操作（externalOnly = true，必须登录）
  const postRes = await rawFetch('POST', `${CONFIG.host}/api/v1${API_PREFIX}/create`,
    { spaceId: CONFIG.spaceId, name: '未登录测试', color: '#000' });
  assert('未登录 - POST create 返回非200', postRes.status !== 200, postRes.status);

  const postRes2 = await rawFetch('POST', `${CONFIG.host}/api/v1${API_PREFIX}/setVisibilityTag`,
    { spaceNodeId: CONFIG.spaceNodeId, visibilityTag: 1 });
  assert('未登录 - POST setVisibilityTag 返回非200', postRes2.status !== 200, postRes2.status);

  restoreSession('admin');
}

// ========== 清理 ==========
async function cleanup() {
  console.log('\n🧹 清理测试数据');

  // 清理 createdTagId2
  if (createdTagId2) {
    await POST(`${API_PREFIX}/${createdTagId2}/delete`);
    console.log(`  ℹ️ 已删除标签 ${createdTagId2}`);
    createdTagId2 = null;
  }

  // 还原 visibility_tag
  await POST(`${API_PREFIX}/setVisibilityTag`, {
    spaceNodeId: CONFIG.spaceNodeId,
    visibilityTag: 0,
  });
  console.log(`  ℹ️ 已还原 visibility_tag=0`);
}

// ========== 执行 ==========
async function main() {
  console.log('🚀 [文档标签] - 接口测试');
  console.log(`   目标: ${CONFIG.host}`);
  console.log('');
  console.log('📋 功能点覆盖清单（来自功能点对照文档）：');
  console.log('  §1. 创建个人标签');
  console.log('  §2. 标签名去重');
  console.log('  §3. 编辑个人标签');
  console.log('  §4. 编辑时去重');
  console.log('  §5. 删除个人标签（级联删除）');
  console.log('  §6. 查询标签列表');
  console.log('  §7. 给文档贴标签');
  console.log('  §8. 防重复绑定');
  console.log('  §9. 取消文档标签');
  console.log('  §10. 设置系统标签');
  console.log('  §11. 系统标签枚举');
  console.log('  §12. 按标签查文档（分页）');
  console.log('  §13. 个人标签归属校验');
  console.log('  §14. 仅本人可见');
  console.log('');

  try {
    await login();
    saveSession('admin');

    // 功能点测试（按依赖顺序）
    await test_1_2_create_tag();       // §1 §2: 创建 + 去重
    await test_3_4_update_tag();       // §3 §4: 编辑 + 编辑时去重
    await test_6_14_list_tags();       // §6 §14: 列表 + 仅本人可见
    await test_7_8_bind_node();        // §7 §8: 绑定 + 防重复绑定
    await test_12_query_nodes();       // §12: 按标签查文档（分页）
    await test_9_unbind_node();        // §9: 取消绑定
    await test_10_11_set_visibility_tag(); // §10 §11: 系统标签
    await test_13_tag_ownership();     // §13: 归属校验（多账号）
    await test_5_delete_tag();         // §5: 删除（级联），放最后

    // 维度补充测试
    await test_param_validation();     // 维度4: 参数校验
    await test_injection();            // 维度5: 注入防护
    await test_not_exist();            // 维度8: 不存在数据
    await test_concurrency();          // 维度9: 并发
    await test_response_structure();   // 维度10: 响应结构
    await test_duplicate_data();       // 维度12: 数据重复检测
    await test_error_code_standard();  // 维度13: 错误码规范性
    await test_unauthenticated();      // 维度7补充: 未登录

    // 清理
    await cleanup();

  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接测试环境，请检查网络');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    process.exit(1);
  }

  console.log(`\n=============================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`=============================`);
  process.exit(failed > 0 ? 1 : 0);
}

main();

