// ========== 维度5：注入防护 + 特殊字符 ==========
async function test_injection() {
  console.log('\n🛡️ 维度5：注入防护 + 特殊字符');

  const injections = [
    "' OR 1=1 --",
    "1; DROP TABLE collabspace_space_node_tag;",
    "' UNION SELECT * FROM collabspace_space_node --",
    "<script>alert(1)</script>",
    "${7*7}",
    "{{constructor.constructor('return this')()}}",
  ];

  for (const payload of injections) {
    // 测试 create 接口的 name 字段
    const res = await POST(`${API_PREFIX}/create`, {
      spaceId: CONFIG.spaceId,
      name: payload.slice(0, 50),
      color: '#000000',
    });
    assert(`注入防护 - create name="${payload.slice(0, 25)}..." 不报500`,
      res.code !== 500, res.code);

    // 如果创建成功了要清理
    if (res.success === true && res.data?.id) {
      await POST(`${API_PREFIX}/${String(res.data.id)}/delete`);
    }
  }

  // 测试 list 的 spaceId 参数
  const specialChars = ['%', '_', '\'', '"', '\\', '&&'];
  for (const ch of specialChars) {
    const res = await GET(`${API_PREFIX}/list?spaceId=${encodeURIComponent(ch)}`);
    assert(`注入防护 - list spaceId="${ch}" 不报500`,
      res.success === true || (res.code && res.code !== 500), res);
  }
}

