// ========== 维度9：并发请求 ==========
async function test_concurrency() {
  console.log('\n🔀 维度9：并发请求');

  const promises = Array.from({ length: 5 }, () =>
    GET(`${API_PREFIX}/list?spaceId=${CONFIG.spaceId}`)
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.success === true);
  assert('并发 - 5个并发 list 请求都成功', allOk);

  // 并发创建不同名称的标签
  const ts = Date.now();
  const createPromises = Array.from({ length: 3 }, (_, i) =>
    POST(`${API_PREFIX}/create`, {
      spaceId: CONFIG.spaceId,
      name: `并发标签${i}_${ts}`,
      color: '#' + String(i).repeat(6).slice(0, 6),
    })
  );
  const createResults = await Promise.all(createPromises);
  const allCreated = createResults.every(r => r.success === true);
  assert('并发 - 3个并发 create 请求都成功', allCreated);

  // 清理
  for (const r of createResults) {
    if (r.data?.id) {
      await POST(`${API_PREFIX}/${String(r.data.id)}/delete`);
    }
  }
}

